function rFinance(){
  const now=new Date(),m=now.getMonth()+1,y=now.getFullYear();
  const ss=DB.settings(),bn1=ss.bankName1||'بنك ١',bn2=ss.bankName2||'بنك ٢',cash=ss.cashName||'كاش';
  const incRows=DB.income2().filter(r=>r.month===m&&r.year===y);
  const expRows=DB.expense2().filter(r=>r.month===m&&r.year===y);
  const salRows=DB.salaries().filter(s=>s.mo===m&&s.yr===y);
  const iT=calcFinTotals(incRows),eT=calcFinTotals(expRows);
  const mSal=salRows.filter(s=>s.paid).reduce((a,b)=>a+(+b.net||0),0);
  const mIn=iT.tt,mEx=eT.tt,mNet=mIn-mEx;
  const yrs=[y-1,y,y+1];const mos=Array.from({length:12},(_,i)=>i+1);
  return`<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px;flex-wrap:wrap;gap:8px">
    <div style="font-size:18px;font-weight:900">💳 الحسابات</div>
    <div style="display:flex;gap:7px;flex-wrap:wrap"><button class="btn bp bsm" onclick="addFinRow('income2')">+ مدخول</button><button class="btn berr bsm" onclick="addFinRow('expense2')">+ مصروف</button></div>
  </div>
  <div class="tabs"><div id="ftab-inc" class="tab act" onclick="switchFinTab('inc')">📥 المدخولات</div><div id="ftab-exp" class="tab" onclick="switchFinTab('exp')">📤 المصاريف</div><div id="ftab-sal" class="tab" onclick="switchFinTab('sal')">💼 الرواتب</div><div id="ftab-sum" class="tab" onclick="switchFinTab('sum')">📊 الملخص</div></div>
  <div id="fin-tab-inc">
    <div class="tw"><div class="ttb">
      <select class="tf" id="finIncM" onchange="filterInc()">${mos.map(i=>`<option value="${i}" ${i===m?'selected':''}>${MNS[i-1]}</option>`).join('')}</select>
      <select class="tf" id="finIncY" onchange="filterInc()">${yrs.map(yr=>`<option value="${yr}" ${yr===y?'selected':''}>${yr}</option>`).join('')}</select>
      <span class="tc">إجمالي: ${fmtM(mIn)}</span></div>
    <div style="overflow-x:auto"><table><thead><tr><th>#</th><th>البيان</th><th>${bn1}</th><th>${bn2}</th><th>${cash}</th><th>الإجمالي</th><th>التاريخ</th><th>بواسطة</th><th>ملاحظات</th><th></th></tr></thead><tbody id="incTb">${rIncRows(incRows,bn1,bn2,cash)}</tbody></table></div></div>
  </div>
  <div id="fin-tab-exp" style="display:none">
    <div class="tw"><div class="ttb">
      <select class="tf" id="finExpM" onchange="filterExp()">${mos.map(i=>`<option value="${i}" ${i===m?'selected':''}>${MNS[i-1]}</option>`).join('')}</select>
      <select class="tf" id="finExpY" onchange="filterExp()">${yrs.map(yr=>`<option value="${yr}" ${yr===y?'selected':''}>${yr}</option>`).join('')}</select>
      <span class="tc">إجمالي: ${fmtM(mEx)}</span></div>
    <div style="overflow-x:auto"><table><thead><tr><th>#</th><th>البيان</th><th>${bn1}</th><th>${bn2}</th><th>${cash}</th><th>الإجمالي</th><th>التاريخ</th><th>بواسطة</th><th>ملاحظات</th><th></th></tr></thead><tbody id="expTb">${rExpRows(expRows,bn1,bn2,cash)}</tbody></table></div></div>
  </div>
  <div id="fin-tab-sal" style="display:none">
    <div class="tw"><div class="ttb">
      <select class="tf" id="finSalM" onchange="filterSal()">${mos.map(i=>`<option value="${i}" ${i===m?'selected':''}>${MNS[i-1]}</option>`).join('')}</select>
      <select class="tf" id="finSalY" onchange="filterSal()">${yrs.map(yr=>`<option value="${yr}" ${yr===y?'selected':''}>${yr}</option>`).join('')}</select>
      <span class="tc">إجمالي: ${fmtM(mSal)}</span></div>
    <div style="overflow-x:auto"><table><thead><tr><th>الموظف</th><th>الشهر</th><th>الأساسي</th><th>إضافات</th><th>خصومات</th><th>الصافي</th><th>الحالة</th><th>بواسطة</th><th>التاريخ</th><th></th></tr></thead><tbody id="salTb">${rSalRows(salRows)}</tbody></table></div></div>
  </div>
  <div id="fin-tab-sum" style="display:none">
    <div class="card"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px"><div class="ct" style="margin:0">📊 ملخص ${MNS[m-1]} ${y}</div><button class="btn bo bsm" onclick="go('fin_summary')">الملخص السنوي ←</button></div>
    <div class="g3" style="gap:12px">
      ${[['📥 مدخولات',mIn,'var(--ok)','var(--okb)'],['📤 مصاريف',mEx,'var(--err)','var(--errb)'],['💹 الصافي',mNet,mNet>=0?'var(--navy)':'var(--err)',mNet>=0?'var(--navy3)':'var(--errb)']].map(([l,v,c,bg])=>`<div style="background:${bg};border-radius:10px;padding:14px;text-align:center"><div style="font-size:11px;color:${c};margin-bottom:4px">${l}</div><div style="font-size:20px;font-weight:900;color:${c}">${fmtM(v)}</div></div>`).join('')}
    </div></div>
  </div>`;
}

