// ══════════════════════════════════════════════════════════
//  ── تحكم تفاعلي: السايدبار + الجداول ──
// ══════════════════════════════════════════════════════════
(function initInteractiveControls(){
  'use strict';

  // ─── 1. سايدبار: سحب وإعادة ترتيب التسميات ───────────
  function setupSidebarDrag(){
    const sb=document.getElementById('sb');
    if(!sb)return;
    // Add hint label once
    if(!sb.querySelector('.sb-drag-hint')){
      const hint=document.createElement('div');
      hint.className='sb-drag-hint';
      hint.textContent='⠿  اسحب التسميات لإعادة الترتيب';
      sb.insertBefore(hint,sb.firstChild);
    }
    let dragSrc=null;
    sb.querySelectorAll('.ni').forEach(ni=>{
      if(ni.dataset.sbDrag)return;
      ni.dataset.sbDrag='1';
      ni.setAttribute('draggable','true');

      ni.addEventListener('dragstart',e=>{
        dragSrc=ni;
        ni.classList.add('sb-dragging');
        e.dataTransfer.effectAllowed='move';
        e.dataTransfer.setData('text/plain',ni.dataset.s||Math.random());
      });
      ni.addEventListener('dragend',()=>{
        dragSrc&&dragSrc.classList.remove('sb-dragging');
        sb.querySelectorAll('.sb-drag-over').forEach(x=>x.classList.remove('sb-drag-over'));
        dragSrc=null;
      });
      ni.addEventListener('dragover',e=>{
        e.preventDefault();
        e.dataTransfer.dropEffect='move';
        if(dragSrc&&ni!==dragSrc)ni.classList.add('sb-drag-over');
      });
      ni.addEventListener('dragleave',()=>ni.classList.remove('sb-drag-over'));
      ni.addEventListener('drop',e=>{
        e.preventDefault();
        ni.classList.remove('sb-drag-over');
        if(!dragSrc||dragSrc===ni)return;
        // Determine insertion point (before or after)
        const r=ni.getBoundingClientRect();
        const mid=r.top+r.height/2;
        if(e.clientY<mid) sb.insertBefore(dragSrc,ni);
        else if(ni.nextSibling) sb.insertBefore(dragSrc,ni.nextSibling);
        else sb.appendChild(dragSrc);
      });
    });
  }

  // ─── 2. الجداول: طي / تعويم / تغيير الحجم ────────────
  function setupTableControls(){
    document.querySelectorAll('.tw').forEach(tw=>{
      if(tw.dataset.twCtrl)return;
      tw.dataset.twCtrl='1';
      const ttb=tw.querySelector('.ttb');
      if(!ttb)return;

      // --- أزرار التحكم ---
      const ctrl=document.createElement('div');
      ctrl.className='tw-ctrl';

      // زر الطي / الفتح
      const colBtn=document.createElement('button');
      colBtn.className='tw-ibtn';
      colBtn.innerHTML='<span>▼</span> طي';
      colBtn.title='طي الجدول أو فتحه';
      let collapsed=false;
      colBtn.addEventListener('click',()=>{
        collapsed=!collapsed;
        tw.classList.toggle('tw-collapsed',collapsed);
        colBtn.innerHTML=collapsed?'<span>▶</span> فتح':'<span>▼</span> طي';
      });
      ctrl.appendChild(colBtn);

      // زر التعويم / السحب
      const floatBtn=document.createElement('button');
      floatBtn.className='tw-ibtn is-grab';
      floatBtn.innerHTML='⠿ تحريك';
      floatBtn.title='اسحب لتعويم الجدول — انقر مرتين للإرساء';
      ctrl.appendChild(floatBtn);

      ttb.appendChild(ctrl);

      // --- Wrapper للتغيير الحجم ---
      const wrapper=document.createElement('div');
      wrapper.className='tw-wrapper';
      // Keep margin from .tw
      const twStyle=getComputedStyle(tw);
      tw.parentNode.insertBefore(wrapper,tw);
      wrapper.appendChild(tw);

      // مقبض تغيير الحجم (زاوية يسار-أسفل، RTL)
      const resizeSE=document.createElement('div');
      resizeSE.className='tw-resize-se';
      resizeSE.title='اسحب لتغيير عرض وارتفاع الجدول';
      wrapper.appendChild(resizeSE);

      // مقبض تغيير الارتفاع فقط (أسفل المنتصف)
      const resizeS=document.createElement('div');
      resizeS.className='tw-resize-s';
      resizeS.title='اسحب لتغيير ارتفاع الجدول';
      wrapper.appendChild(resizeS);

      // --- حالة التعويم ---
      let floating=false, ph=null;

      function startFloat(){
        if(floating)return;
        const rect=wrapper.getBoundingClientRect();
        ph=document.createElement('div');
        ph.className='tw-ph';
        ph.style.height=rect.height+'px';
        wrapper.parentNode.insertBefore(ph,wrapper.nextSibling);
        wrapper.style.left=rect.left+'px';
        wrapper.style.top=rect.top+'px';
        wrapper.style.width=rect.width+'px';
        wrapper.classList.add('tw-floating');
        floating=true;
        floatBtn.innerHTML='⊙ إرساء';
        floatBtn.title='انقر لإرساء الجدول في مكانه';
        floatBtn.classList.remove('is-grab');
      }

      function dockFloat(){
        if(!floating)return;
        wrapper.style.left='';wrapper.style.top='';wrapper.style.width='';wrapper.style.height='';
        wrapper.classList.remove('tw-floating');
        floating=false;
        if(ph){ph.remove();ph=null;}
        floatBtn.innerHTML='⠿ تحريك';
        floatBtn.title='اسحب لتعويم الجدول — انقر مرتين للإرساء';
        floatBtn.classList.add('is-grab');
      }

      // سحب لتعويم وتحريك
      floatBtn.addEventListener('mousedown',e=>{
        if(e.button!==0)return;
        e.preventDefault();
        if(!floating)startFloat();
        floatBtn.classList.add('dragging');
        const sx=e.clientX,sy=e.clientY;
        const sl=parseFloat(wrapper.style.left)||0;
        const st=parseFloat(wrapper.style.top)||0;
        const mv=ev=>{
          wrapper.style.left=(sl+ev.clientX-sx)+'px';
          wrapper.style.top=(st+ev.clientY-sy)+'px';
        };
        const up=()=>{
          floatBtn.classList.remove('dragging');
          document.removeEventListener('mousemove',mv);
          document.removeEventListener('mouseup',up);
        };
        document.addEventListener('mousemove',mv);
        document.addEventListener('mouseup',up);
      });

      // نقرة مزدوجة للإرساء
      floatBtn.addEventListener('dblclick',()=>{
        if(floating)dockFloat();
        else startFloat();
      });

      // تغيير الحجم: زاوية (عرض + ارتفاع)
      resizeSE.addEventListener('mousedown',e=>{
        if(e.button!==0)return;
        e.preventDefault();
        const sx=e.clientX,sy=e.clientY;
        const sw=wrapper.offsetWidth,sh=wrapper.offsetHeight;
        const getScrollEl=()=>tw.querySelector('div[style*="overflow-x"]')||tw.querySelector('div[style*="overflow"]');
        const mv=ev=>{
          const dw=sx-ev.clientX; // RTL: drag left = wider
          const dh=ev.clientY-sy;
          const newW=Math.max(300,sw+dw);
          const newH=Math.max(120,sh+dh);
          if(!floating)wrapper.style.position='relative';
          wrapper.style.width=newW+'px';
          wrapper.style.height=newH+'px';
          const sc=getScrollEl();
          if(sc)sc.style.maxHeight=Math.max(80,newH-56)+'px';
          else tw.style.maxHeight=newH+'px';
        };
        const up=()=>{document.removeEventListener('mousemove',mv);document.removeEventListener('mouseup',up)};
        document.addEventListener('mousemove',mv);
        document.addEventListener('mouseup',up);
      });

      // تغيير الحجم: ارتفاع فقط
      resizeS.addEventListener('mousedown',e=>{
        if(e.button!==0)return;
        e.preventDefault();
        const sy=e.clientY,sh=wrapper.offsetHeight;
        const getScrollEl=()=>tw.querySelector('div[style*="overflow-x"]')||tw.querySelector('div[style*="overflow"]');
        const mv=ev=>{
          const dh=ev.clientY-sy;
          const newH=Math.max(120,sh+dh);
          wrapper.style.height=newH+'px';
          const sc=getScrollEl();
          if(sc)sc.style.maxHeight=Math.max(80,newH-56)+'px';
          else tw.style.maxHeight=newH+'px';
        };
        const up=()=>{document.removeEventListener('mousemove',mv);document.removeEventListener('mouseup',up)};
        document.addEventListener('mousemove',mv);
        document.addEventListener('mouseup',up);
      });
    });
  }

  // ─── 3. مراقبة التغييرات الديناميكية ─────────────────
  const pc=document.getElementById('pc');
  if(pc){
    new MutationObserver(()=>{
      setupTableControls();
    }).observe(pc,{childList:true,subtree:false});
  }

  // ─── 4. تشغيل عند الدخول ──────────────────────────────
  // تفعيل السايدبار بعد الدخول
  const loginCheck=setInterval(()=>{
    const app=document.getElementById('app');
    if(app&&app.classList.contains('on')){
      clearInterval(loginCheck);
      setupSidebarDrag();
      setupTableControls();
      // Re-init sidebar after any page navigation
      const origGo=window.go;
      if(typeof origGo==='function'){
     
        window.go = function(...args) {
          origGo(...args);
          setTimeout(()=>{setupSidebarDrag();setupTableControls();}, 120);
        };
      }
    }
  }, 300);

})();

